// API client for the PRAHARI backend, with a self-contained STATIC mode.
//
//  * Dynamic mode (default): talks to the live FastAPI backend. Set
//    VITE_API_BASE_URL for a deployed backend, or use the dev proxy locally.
//  * Static mode (VITE_STATIC_DEMO=1): reads pre-computed JSON bundled in
//    /public/demo, so the deployed site runs with no backend to keep alive —
//    it can never go down during judging. The JSON is the exact backend output
//    (generated by backend/scripts/export_demo.py).
const BASE = import.meta.env.VITE_API_BASE_URL || ''
const STATIC = import.meta.env.VITE_STATIC_DEMO === '1'

async function jget(url) {
  const res = await fetch(url)
  if (!res.ok) throw new Error(`GET ${url} → ${res.status}`)
  return res.json()
}
const demo = (p) => jget(`${import.meta.env.BASE_URL}demo/${p}`)

async function get(path) { return jget(`${BASE}${path}`) }
async function post(path, body) {
  const res = await fetch(`${BASE}${path}`, {
    method: 'POST', headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(body),
  })
  if (!res.ok) throw new Error(`POST ${path} → ${res.status}`)
  return res.json()
}

// Static caches (fetched once).
let _events = null, _briefs = null, _interdictions = null

// Client-side Ask-PRAHARI mirroring the backend's deterministic retrieval.
const STOP = new Set(['the', 'a', 'an', 'of', 'for', 'to', 'and', 'or', 'is', 'are', 'what',
  'how', 'why', 'in', 'on', 'about', 'does', 'do', 'with', 'bangladesh'])
async function staticAsk(question, language) {
  _events = _events || await demo('drishti/events.json')
  const qtok = [...new Set(question.toLowerCase().replace(/\?/g, ' ').split(/\s+/))]
    .filter((w) => w.length > 2 && !STOP.has(w))
  const scoreOf = (s) => {
    const hay = [s.event.title, s.event.summary, ...s.event.actors, ...s.event.sectors].join(' ').toLowerCase()
    return qtok.reduce((n, w) => n + (hay.includes(w) ? 1 : 0), 0)
  }
  let matches = _events.events.map((s) => [scoreOf(s), s]).filter(([n]) => n > 0)
    .sort((a, b) => b[0] - a[0]).slice(0, 4).map(([, s]) => s)
  // General question (no keyword hit) → ground on the most relevant live events.
  const general = matches.length === 0
  if (general) matches = _events.events.slice(0, 3)

  const top = matches[0]
  const list = matches.slice(0, 3).map((m) => `“${m.event.title}” (${Math.round(m.relevance_score)}/100)`)
  let answer
  if (language === 'bn') {
    answer = general
      ? `এই মুহূর্তে বাংলাদেশের জন্য সবচেয়ে গুরুত্বপূর্ণ বিষয়গুলো: ${list.join('; ')}। প্রতিটি ঘটনায় ক্লিক করে করণীয়/বর্জনীয় ব্রিফ ও চার্ট দেখুন।`
      : `সবচেয়ে প্রাসঙ্গিক ঘটনা: “${top.event.title}” (স্কোর ${Math.round(top.relevance_score)}/১০০)। বিস্তারিত সুপারিশের জন্য এর প্রতিবেদন খুলুন।`
  } else {
    answer = general
      ? `The most pressing items for Bangladesh right now: ${list.join('; ')}. Open any event for its Do/Avoid brief, charts, and evidence.`
      : `The most relevant event is “${top.event.title}” (Bangladesh Relevance ${Math.round(top.relevance_score)}/100, severity ${top.severity}). ${top.event.summary} Open its report for specific recommendations.`
  }
  const conf = general ? 0.55 : Math.min(0.9, 0.3 + matches.length * 0.2)
  return {
    question, language, answer,
    referenced_events: matches.map((s) => s.event.id),
    evidence: matches.map((s) => ({ source: s.event.source, detail: s.event.title, url: s.event.url })),
    meta: { confidence: conf, confidence_label: conf >= 0.75 ? 'high' : conf >= 0.5 ? 'medium' : 'low', model_version: 'drishti-ask-static/0.1.0' },
    answer_source: 'deterministic',
  }
}

export const api = {
  // DRISHTI
  events: async ({ sector, severity, minScore } = {}) => {
    if (STATIC) {
      const d = await demo('drishti/events.json')
      let ev = d.events
      if (sector) ev = ev.filter((s) => s.event.sectors.includes(sector))
      if (severity) ev = ev.filter((s) => s.severity === severity)
      if (minScore) ev = ev.filter((s) => s.relevance_score >= minScore)
      return { ...d, events: ev, total: ev.length }
    }
    const q = new URLSearchParams()
    if (sector) q.set('sector', sector)
    if (severity) q.set('severity', severity)
    if (minScore) q.set('min_score', minScore)
    return get(`/api/drishti/events?${q.toString()}`)
  },
  brief: async (eventId, language = 'en') => {
    if (STATIC) {
      _briefs = _briefs || await demo('drishti/briefs.json')
      return _briefs[`${eventId}:${language}`] || _briefs[`${eventId}:en`]
    }
    return get(`/api/drishti/events/${encodeURIComponent(eventId)}/brief?language=${language}`)
  },
  econ: () => jget(`${import.meta.env.BASE_URL}demo/drishti/econ.json`),
  ask: async (question, language = 'en') => {
    // Prefer a live backend (real Gemini) when configured; fall back to the
    // client-side grounded answer so the demo never breaks.
    const base = import.meta.env.VITE_API_BASE_URL
    if (base) {
      try { return await post('/api/drishti/ask', { question, language }) } catch { /* fall through */ }
    }
    return STATIC ? staticAsk(question, language) : post('/api/drishti/ask', { question, language })
  },

  // RAKKHOK
  readiness: () => (STATIC ? demo('rakkhok/readiness.json') : get('/api/rakkhok/readiness')),
  assets: (force) => (STATIC ? demo('rakkhok/assets.json') : get(`/api/rakkhok/assets${force ? `?force=${force}` : ''}`)),
  rulRanking: (limit = 8) => (STATIC ? demo('rakkhok/rul-ranking.json') : get(`/api/rakkhok/rul-ranking?limit=${limit}`)),
  fleetAlerts: () => (STATIC ? demo('rakkhok/alerts.json') : get('/api/rakkhok/alerts')),

  // SHOMUDRO
  picture: () => (STATIC ? demo('shomudro/picture.json') : get('/api/shomudro/picture')),
  interdiction: async (targetId) => {
    if (STATIC) {
      _interdictions = _interdictions || await demo('shomudro/interdictions.json')
      return _interdictions[targetId]
    }
    return get(`/api/shomudro/interdiction/${encodeURIComponent(targetId)}`)
  },
}
